from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects describing an artist (or related entity)
    into a single fluent English sentence.
    """
    if not triples:
        return ""

    # Main entity is the subject of the first triple
    main_subject = triples[0].subject

    # Helper to turn a predicate/object into a natural clause.
    # The clause now includes the subject, allowing proper phrasing and
    # handling of predicates that require inversion (e.g., derivative, parentCompany).
    def clause(t: Triple) -> str:
        s = t.subject
        o = t.object.strip('"')
        p = t.predicate

        # Direct mappings where subject stays first
        if p in ("associatedBand/associatedMusicalArtist",):
            return f"{s} is associated with {o}"
        if p == "background":
            return f"{s} is a {o}"
        if p == "genre":
            return f"{s} performs {o.lower()} music"
        if p == "instrument":
            return f"{s} plays the {o}"
        if p == "origin":
            return f"{s} originates from {o}"
        if p == "birthDate":
            return f"{s} was born on {o}"
        if p == "birthPlace":
            return f"{s} was born in {o}"
        if p == "birthYear":
            return f"{s} was born in {o}"
        if p == "occupation":
            return f"{s} works as {o}"
        if p == "recordLabel":
            return f"{s} is signed to {o}"
        if p == "deathPlace":
            return f"{s} died in {o}"
        if p == "deathDate":
            return f"{s} died on {o}"
        if p == "nationality":
            return f"{s} is {o}"
        if p == "professionalField":
            return f"{s} works in {o}"
        if p in ("language", "officialLanguage"):
            return f"{s} speaks {o}"
        if p == "capital":
            return f"{s} has capital {o}"
        if p == "currency":
            return f"{s} uses the {o}"
        if p == "populationDensity":
            return f"{s} has a population density of {o}"
        # Inverted relations where object should be the subject
        if p == "derivative":
            return f"{o} is derived from {s}"
        if p == "parentCompany":
            return f"{o} is the parent company of {s}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "governingBody":
            return f"{s} is governed by {o}"
        if p == "leader":
            return f"{s} is led by {o}"
        if p == "leaderTitle":
            return f"{s} has leader title {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "ethnicGroup":
            return f"{s} has ethnic group {o}"
        if p == "bandMember":
            return f"{s} includes member {o}"
        if p == "anthem":
            return f"The anthem of {s} is {o}"
        if p == "demonym":
            return f"The demonym for {s} is {o}"
        if p == "meaning":
            return f"The meaning of {s} is {o}"
        if p == "longName":
            return f"The long name of {s} is {o}"
        if p == "areaTotal":
            return f"{s} covers an area of {o}"
        if p == "foundingDate":
            return f"{s} was founded on {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at {o} meters above sea level"
        if p == "postalCode":
            return f"The postal code of {s} is {o}"
        if p == "distributionCompany" or p == "distributingCompany":
            return f"{s} is distributed by {o}"
        if p == "training":
            return f"{s} was trained at {o}"
        # default fallback
        pred_readable = p.replace("_", " ")
        return f"{s} {pred_readable} {o}"

    # Build clauses for all triples
    clauses = [clause(t) for t in triples]

    # Combine clauses into a fluent sentence
    if len(clauses) == 1:
        body = clauses[0]
    else:
        body = ", ".join(clauses[:-1]) + ", and " + clauses[-1]

    # Capitalize first letter of the sentence
    sentence = f"{main_subject} {body}."
    return sentence

# EVOLVE-BLOCK-END

